ValidationRule.errorConditionFormula:
OR(
    /* Primary must be 10 digits */
    AND(
        NOT(ISBLANK(Primary_Mobile__c)),
        NOT(REGEX(Primary_Mobile__c, "^[0-9]{10}$"))
    ),

    /* Secondary must be 10 digits */
    AND(
        NOT(ISBLANK(Secondary_Mobile__c)),
        NOT(REGEX(Secondary_Mobile__c, "^[0-9]{10}$"))
    ),

    /* Both numbers should not be same */
    AND(
        NOT(ISBLANK(Primary_Mobile__c)),
        NOT(ISBLANK(Secondary_Mobile__c)),
        Primary_Mobile__c = Secondary_Mobile__c
    )
)
